class HybridWebViewController: UIViewController {
    private var webView: WKWebView!
    private var cameraPermissionGranted = false
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        loadWebContent()
    }
    
    private func setupWebView() {
        let configuration = WKWebViewConfiguration()
        configuration.allowsInlineMediaPlayback = true
        configuration.mediaTypesRequiringUserActionForPlayback = []
        configuration.preferences.javaScriptEnabled = true
        configuration.preferences.setValue(true, forKey: "allowFileAccessFromFileURLs")
        
        configuration.userContentController.add(self, name: "cameraRequest")
        configuration.userContentController.add(self, name: "pushNotificationRequest")
        configuration.userContentController.add(self, name: "inAppPurchaseRequest")
        
        webView = WKWebView(frame: view.bounds, configuration: configuration)
        webView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        webView.navigationDelegate = self
        webView.uiDelegate = self
        view.addSubview(webView)
    }
    
    private func loadWebContent() {
        guard let url = URL(string: "https://yourwebsite.com") else { return }
        let request = URLRequest(url: url, cachePolicy: .reloadIgnoringLocalCacheData, timeoutInterval: 30)
        webView.load(request)
    }
    
    private func requestCameraAccess(completion: @escaping (Bool) -> Void) {
        AVCaptureDevice.requestAccess(for: .video) { granted in
            DispatchQueue.main.async {
                self.cameraPermissionGranted = granted
                completion(granted)
            }
        }
    }
    
    private func requestPushNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { granted, error in
            DispatchQueue.main.async {
                if let error = error {
                    print("Push notification permission error: \(error)")
                }
            }
        }
    }
    
    private func handleInAppPurchase(productId: String) {
        guard SKPaymentQueue.canMakePayments() else {
            webView.evaluateJavaScript("handleInAppPurchaseError('Payments not enabled')") { _, _ in }
            return
        }
        
        let payment = SKPayment(product: SKProduct())
        SKPaymentQueue.default().add(self)
    }
}

extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }
        
        switch message.name {
        case "cameraRequest":
            requestCameraAccess { granted in
                let result = granted ? "success" : "denied"
                self.webView.evaluateJavaScript("handleCameraResult('\(result)')") { _, _ in }
            }
            
        case "pushNotificationRequest":
            requestPushNotificationPermission()
            webView.evaluateJavaScript("handlePushNotificationResult('success')") { _, _ in }
            
        case "inAppPurchaseRequest":
            if let productId = body["productId"] as? String {
                handleInAppPurchase(productId: productId)
            }
            
        default:
            break
        }
    }
}

